.settings-sidebar .nav-link {
    text-align: left;
    padding: 0.75rem 1.25rem;
    border-radius: 0.375rem;
    color: var(--bs-body-color);
    font-weight: 500;
    border: none;
    background: none;
    width: 100%;
    transition: background-color 0.15s, color 0.15s;
}

.settings-sidebar .nav-link:hover {
    background-color: var(--bs-tertiary-bg);
}

.settings-sidebar .nav-link.active {
    background-color: var(--bs-primary);
    color: #fff;
}

@using sv_d88a7b92359a4204bf42ead2386801c3.Models

<section>
    <h4 class="mb-4">Profile</h4>

    <div class="d-flex align-items-start gap-4 mb-4">
        <div class="avatar-preview">
            @if (!string.IsNullOrWhiteSpace(_avatarUrl))
            {
                <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" width="80" height="80" />
            }
            else
            {
                <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center text-white"
                     style="width:80px;height:80px;font-size:2rem;">
                    👤
                </div>
            }
        </div>
        <div class="flex-grow-1">
            <label class="form-label text-muted small">Avatar URL</label>
            <input type="url" class="form-control form-control-sm" @bind="_avatarUrl" />
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" @bind="_displayName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="_email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="4" @bind="_bio"></textarea>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
            <span class="me-2">✅</span> Profile saved successfully.
        </div>
    }
</section>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _saving;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_saving)
        {
            CopyFromProfile();
        }
    }

    private void CopyFromProfile()
    {
        _displayName = Profile!.DisplayName;
        _email = Profile.Email;
        _avatarUrl = Profile.AvatarUrl;
        _bio = Profile.Bio;
    }

    private async Task Save()
    {
        _saving = true;
        _showSuccess = false;

        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await OnSave.InvokeAsync(updated);

        _saving = false;
        _showSuccess = true;

        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard()
    {
        CopyFromProfile();
        _showSuccess = false;
    }
}

@using sv_d88a7b92359a4204bf42ead2386801c3.Models

<section>
    <h4 class="mb-4">Notifications</h4>

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    @if (_channels.Count > 0)
    {
        <h6 class="mb-3">Muted Channels</h6>
        <div class="list-group mb-4">
            @foreach (var channel in _channels)
            {
                <label class="list-group-item d-flex align-items-center gap-2">
                    <input class="form-check-input mt-0" type="checkbox"
                           checked="@channel.Muted"
                           @onchange="() => ToggleChannel(channel.Name)" />
                    <span>@channel.Name</span>
                    @if (channel.Muted)
                    {
                        <span class="badge bg-secondary ms-auto">Muted</span>
                    }
                </label>
            }
        </div>
    }

    <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Save Preferences
    </button>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
            <span class="me-2">✅</span> Notification preferences saved.
        </div>
    }
