    <h4 class="mb-4">Appearance</h4>

    <div class="mb-4">
        <h6>Theme</h6>
        <div class="btn-group" role="group" aria-label="Theme selector">
            @foreach (var theme in _themes)
            {
                <input type="radio" class="btn-check" name="theme"
                       id="theme-@theme" autocomplete="off"
                       checked="@(_theme == theme)"
                       @onchange="() => _theme = theme" />
                <label class="btn btn-outline-primary" for="theme-@theme">@theme</label>
            }
        </div>
    </div>

    <div class="mb-4">
        <h6>Font Size</h6>
        <div class="btn-group" role="group" aria-label="Font size selector">
            @foreach (var size in _fontSizes)
            {
                <input type="radio" class="btn-check" name="fontSize"
                       id="fontSize-@size" autocomplete="off"
                       checked="@(_fontSize == size)"
                       @onchange="() => _fontSize = size" />
                <label class="btn btn-outline-secondary" for="fontSize-@size">@size</label>
            }
        </div>
    </div>

    <div class="mb-4">
        <label class="form-label"><h6 class="d-inline">Language</h6></label>
        <select class="form-select w-auto" @bind="_language">
            @foreach (var lang in _languages)
            {
                <option value="@lang.Value">@lang.Label</option>
            }
        </select>
    </div>

    <div class="mb-4">
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
            <label class="form-check-label" for="compactMode">Compact Mode</label>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header">
            <h6 class="mb-0">Live Preview</h6>
        </div>
        <div class="card-body @GetPreviewClasses()" style="@GetPreviewStyles()">
            <h5>Sample Heading</h5>
            <p>This is how your content will look with the selected settings.</p>
            <button class="btn btn-primary btn-sm">Sample Button</button>
            <span class="badge bg-info ms-2">Badge</span>
        </div>
    </div>

    <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Save
    </button>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
            <span class="me-2">✅</span> Appearance settings saved.
        </div>
    }
</section>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _saving;
    private bool _showSuccess;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly (string Value, string Label)[] _languages =
    [
        ("en", "English"),
        ("es", "Spanish"),
        ("fr", "French"),
        ("de", "German"),
        ("ja", "Japanese"),
        ("zh", "Chinese")
    ];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_saving)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_theme == "Dark")
            classes.Add("bg-dark text-light");
        else if (_theme == "Light")
            classes.Add("bg-light text-dark");
        else
            classes.Add("bg-body-secondary");

        if (_compactMode)
            classes.Add("p-2");
        else
            classes.Add("p-3");

        return string.Join(' ', classes);
    }

    private string GetPreviewStyles()
    {
        var size = _fontSize switch
        {
            "Small" => "0.85rem",
            "Large" => "1.15rem",
            _ => "1rem"
        };
        return $"font-size: {size}; transition: all 0.3s ease;";
    }

    private async Task Save()
    {
        _saving = true;
        _showSuccess = false;

        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);

        _saving = false;
        _showSuccess = true;

        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

