{"file_text": "<div class="card mb-4">
    <div class="card-header d-flex align-items-center justify-content-between"
         role="button"
         @onclick="() => _expanded = !_expanded">
        <h6 class="mb-0">Change Password</h6>
        <span class="@(_expanded ? "rotate-icon" : "")">▶</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password"
                       class="form-control @(_validationError is not null ? "is-invalid" : "")"
                       @bind="_confirmPassword" />
                @if (_validationError is not null)
                {
                    <div class="invalid-feedback">@_validationError</div>
                }
            </div>

            <button class="btn btn-warning" @onclick="Submit" disabled="@_submitting">
                @if (_submitting)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>

            @if (_successMessage is not null)
            {
                <div class="alert alert-success mt-3">@_successMessage</div>
            }

            @if (_errorMessage is not null)
            {
                <div class="alert alert-danger mt-3">@_errorMessage</div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string CurrentPassword, string NewPassword)> OnSubmit { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _validationError;
    private string? _successMessage;
    private string? _errorMessage;
    private bool _submitting;

    private async Task Submit()
    {
        _validationError = null;
        _successMessage = null;
        _errorMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _validationError = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _validationError = "New password and confirmation do not match.";
            return;
        }

        _submitting = true;

        try
        {
            await OnSubmit.InvokeAsync((_currentPassword, _newPassword));
            _successMessage = "Password updated successfully.";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _submitting = false;
        }
    }
}
