@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter] public EventCallback<(string CurrentPassword, string NewPassword)> OnPasswordChange { get; set; }
    [Parameter] public EventCallback<bool> OnToggle2FA { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private async Task HandlePasswordChange((string CurrentPassword, string NewPassword) args)
    {
        await OnPasswordChange.InvokeAsync(args);
    }

    private async Task HandleToggle2FA(ChangeEventArgs e)
    {
        var enabled = (bool)(e.Value ?? false);
        await OnToggle2FA.InvokeAsync(enabled);
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
    }
}
