@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _saving;
    private bool _showSuccess;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly (string Value, string Label)[] _languages =
    [
        ("en", "English"),
        ("es", "Spanish"),
        ("fr", "French"),
        ("de", "German"),
        ("ja", "Japanese"),
        ("zh", "Chinese")
    ];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_saving)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_theme == "Dark")
            classes.Add("bg-dark text-light");
        else if (_theme == "Light")
            classes.Add("bg-light text-dark");
        else
            classes.Add("bg-body-secondary");

        if (_compactMode)
            classes.Add("p-2");
        else
            classes.Add("p-3");

        return string.Join(' ', classes);
    }

    private string GetPreviewStyles()
    {
        var size = _fontSize switch
        {
            "Small" => "0.85rem",
            "Large" => "1.15rem",
            _ => "1rem"
        };
        return $"font-size: {size}; transition: all 0.3s ease;";
    }

    private async Task Save()
    {
        _saving = true;
        _showSuccess = false;

        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);

        _saving = false;
        _showSuccess = true;

        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}
