@using sv_d88a7b92359a4204bf42ead2386801c3.Models

<section>
    <h4 class="mb-4">Notifications</h4>

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    @if (_channels.Count > 0)
    {
        <h6 class="mb-3">Muted Channels</h6>
        <div class="list-group mb-4">
            @foreach (var channel in _channels)
            {
                <label class="list-group-item d-flex align-items-center gap-2">
                    <input class="form-check-input mt-0" type="checkbox"
                           checked="@channel.Muted"
                           @onchange="() => ToggleChannel(channel.Name)" />
                    <span>@channel.Name</span>
                    @if (channel.Muted)
                    {
                        <span class="badge bg-secondary ms-auto">Muted</span>
                    }
                </label>
            }
        </div>
    }

    <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Save Preferences
    </button>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
            <span class="me-2">✅</span> Notification preferences saved.
        </div>
    }
</section>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public List<string> AvailableChannels { get; set; } = [];
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelState> _channels = [];
    private bool _saving;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_saving)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;

            var allChannels = AvailableChannels
                .Union(Prefs.MutedChannels)
                .Distinct()
                .OrderBy(c => c)
                .ToList();

            _channels = allChannels
                .Select(c => new ChannelState(c, Prefs.MutedChannels.Contains(c)))
                .ToList();
        }
    }

    private void ToggleChannel(string name)
    {
        var ch = _channels.FirstOrDefault(c => c.Name == name);
        if (ch is not null)
        {
            ch.Muted = !ch.Muted;
        }
    }

    private async Task Save()
    {
        _saving = true;
        _showSuccess = false;

        var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
        await OnSave.InvokeAsync(updated);

        _saving = false;
        _showSuccess = true;

        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private class ChannelState(string name, bool muted)
    {
        public string Name { get; } = name;
        public bool Muted { get; set; } = muted;
    }
}

