@using sv_d88a7b92359a4204bf42ead2386801c3.Models

@if (Sessions is { Count: > 0 })
{
    <div class="table-responsive">
        <table class="table table-striped align-middle">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    var isCurrent = session.Id == CurrentSessionId;
                    <tr>
                        <td>
                            @session.Device
                            @if (isCurrent)
                            {
                                <span class="badge bg-success ms-2">Current</span>
                            }
                        </td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("g")</td>
                        <td>
                            @if (!isCurrent)
                            {
                                <button class="btn btn-outline-danger btn-sm"
                                        @onclick="() => PromptRevoke(session)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (_sessionToRevoke is not null)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>
                        Are you sure you want to revoke the session on
                        <strong>@_sessionToRevoke.Device</strong> from
                        <strong>@_sessionToRevoke.Location</strong>?
                    </p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Revoke
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
        _revoking = false;
        _sessionToRevoke = null;
    }
}

@using sv_d88a7b92359a4204bf42ead2386801c3.Models

<section>
    <h4 class="mb-4">Security</h4>

    <ChangePasswordPanel OnSubmit="HandlePasswordChange" />

    <div class="card mb-4">
        <div class="card-body d-flex align-items-center justify-content-between">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <small class="text-muted">
                    @if (Settings?.TwoFactorEnabled == true)
                    {
                        <span class="text-success">● Enabled</span>
                    }
                    else
                    {
                        <span class="text-danger">● Disabled</span>
                    }
                </small>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox"
                       checked="@(Settings?.TwoFactorEnabled ?? false)"
                       @onchange="HandleToggle2FA" />
            </div>
        </div>
    </div>

    @if (Settings?.LastPasswordChange is not null)
    {
        <p class="text-muted small mb-4">
            Last password change: @Settings.LastPasswordChange.Value.ToString("f")
        </p>
    }

    <h5 class="mb-3">Active Sessions</h5>
    <ActiveSessionsTable Sessions="@Settings?.Sessions"
                         CurrentSessionId="@CurrentSessionId"
                         OnRevoke="HandleRevokeSession" />
</section>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter] public EventCallback<(string CurrentPassword, string NewPassword)> OnPasswordChange { get; set; }
    [Parameter] public EventCallback<bool> OnToggle2FA { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private async Task HandlePasswordChange((string CurrentPassword, string NewPassword) args)
    {
        await OnPasswordChange.InvokeAsync(args);
    }

    private async Task HandleToggle2FA(ChangeEventArgs e)
    {
        var enabled = (bool)(e.Value ?? false);
        await OnToggle2FA.InvokeAsync(enabled);
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
    }
}

