@page "/settings"
@rendermode InteractiveServer
@using sv_d88a7b92359a4204bf42ead2386801c3.Models
@using sv_d88a7b92359a4204bf42ead2386801c3.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<h2 class="mb-4">Settings</h2>

@if (_loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading settings...</span>
        </div>
    </div>
}
else
{
    <div class="settings-layout">
        <aside class="settings-nav">
            <SettingsSidebar ActiveSection="@_activeSection"
                            OnSectionChanged="section => _activeSection = section" />
        </aside>

        <div class="settings-content">
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="@_profile" OnSave="SaveProfile" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@_notificationPrefs"
                                          AvailableChannels="@_availableChannels"
                                          OnSave="SaveNotifications" />
                    break;
                case "Security":
                    <SecuritySection Settings="@_security"
                                     CurrentSessionId="@_currentSessionId"
                                     OnPasswordChange="HandlePasswordChange"
                                     OnToggle2FA="HandleToggle2FA"
                                     OnRevokeSession="HandleRevokeSession" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@_appearance" OnSave="SaveAppearance" />
                    break;
            }
        </div>
    </div>
}

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;
    private string? _currentSessionId;

    // Channels available in the system for muting
    private List<string> _availableChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _loading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notificationPrefs = notifTask.Result;
        _security = securityTask.Result;
        _appearance = appearanceTask.Result;

        // Treat the first session as the current one
        _currentSessionId = _security.Sessions.FirstOrDefault()?.Id;
    }

    private async Task SaveProfile(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotifications(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
    }

    private async Task HandlePasswordChange((string CurrentPassword, string NewPassword) args)
    {
        await SettingsService.ChangePasswordAsync(args.CurrentPassword, args.NewPassword);
        // Reload security settings to get updated LastPasswordChange
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleToggle2FA(bool enabled)
    {
        // Save a new SecuritySettings with the toggled value; sessions and last change are unchanged
        var updated = _security! with { TwoFactorEnabled = enabled };
        _security = updated;
        StateHasChanged();
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearance(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
    }
}

.settings-layout {
    display: flex;
    gap: 2rem;
    min-height: 500px;
}

.settings-nav {
    flex: 0 0 200px;
    border-right: 1px solid var(--bs-border-color);
    padding-right: 1rem;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

@media (max-width: 768px) {
    .settings-layout {
        flex-direction: column;
    }

    .settings-nav {
        flex: none;
        border-right: none;
        border-bottom: 1px solid var(--bs-border-color);
        padding-right: 0;
        padding-bottom: 1rem;
    }
}

